\\\\\"\\\\\\\"\\\\\\\"\\\\n早晨之星K线形态识别\\\\n\\\\\\\"\\\\\\\"\\\\\\\"\\\\nimport akshare as ak\\\\nimport pandas as pd\\\\nfrom datetime import datetime, timedelta\\\\nimport time\\\\n\\\\ndef get_chinext_stocks():\\\\n    \\\\\\\"\\\\\\\"\\\\\\\"获取创业板股票列表\\\\\\\"\\\\\\\"\\\\\\\"\\\\n    try:\\\\n        stock_info = ak.stock_info_a_code_name()\\\\n        # 创业板代码以300或301开头\\\\n        chinext = stock_info[stock_info['code'].str.startswith(('300', '301'))]\\\\n        return chinext['code'].tolist()\\\\n    except Exception as e:\\\\n        print(f\\\\\\\"获取创业板股票列表失败: {e}\\\\\\\")\\\\n        return []\\\\n\\\\ndef get_stock_data(stock_code, days=90):\\\\n    \\\\\\\"\\\\\\\"\\\\\\\"获取股票K线数据\\\\\\\"\\\\\\\"\\\\\\\"\\\\n    try:\\\\n        # 获取历史数据\\\\n        df = ak.stock_zh_a_hist(symbol=stock_code, period=\\\\\\\"daily\\\\\\\", adjust=\\\\\\\"qfq\\\\\\\")\\\\n        if df is None or len(df) == 0:\\\\n            return None\\\\n\\\\n        # 重命名列\\\\n        df = df.rename(columns={\\\\n            '日期': 'date',\\\\n            '开盘': 'open',\\\\n            '收盘': 'close',\\\\n            '最高': 'high',\\\\n            '最低': 'low',\\\\n            '成交量': 'volume'\\\\n        })\\\\n\\\\n        # 转换日期格式\\\\n        df['date'] = pd.to_datetime(df['date'])\\\\n        df = df.sort_values('date', ascending=True)\\\\n\\\\n        # 取最近的数据\\\\n        df = df.tail(days)\\\\n\\\\n        return df\\\\n    except Exception as e:\\\\n        print(f\\\\\\\"获取股票 {stock_code} 数据失败: {e}\\\\\\\")\\\\n        return None\\\\n\\\\ndef calculate_body_ratio(open_price, close_price, high_price, low_price):\\\\n    \\\\\\\"\\\\\\\"\\\\\\\"\\\\n    计算实体占比\\\\n    实体 = |收盘 - 开盘|\\\\n    振幅 = 最高 - 最低\\\\n    实体占比 = 实体 / 振幅\\\\n    \\\\\\\"\\\\\\\"\\\\\\\"\\\\n    body = abs(close_price - open_price)\\\\n    amplitude = high_price - low_price\\\\n    if amplitude == 0:\\\\n        return 0\\\\n    return body / amplitude\\\\n\\\\ndef check_morning_star(df, i):\\\\n    \\\\\\\"\\\\\\\"\\\\\\\"\\\\n    检查第i天开始的3天是否构成早晨之星形态\\\\n\\\\n    条件：\\\\n    1. 第1天：大阴线（跌幅>3%，实体占比>70%）\\\\n    2. 第2天：小K线（涨跌幅绝对值<1.5%）\\\\n    3. 第3天：大阳线（涨幅>3%，实体占比>70%，收盘价高于第1天实体中点）\\\\n    \\\\\\\"\\\\\\\"\\\\\\\"\\\\n    if i + 2 >= len(df):\\\\n        return False\\\\n\\\\n    day1 = df.iloc[i]\\\\n    day2 = df.iloc[i + 1]\\\\n    day3 = df.iloc[i + 2]\\\\n\\\\n    # 第1天：大阴线\\\\n    day1_change = (day1['close'] - day1['open']) / day1['open'] * 100\\\\n    day1_body_ratio = calculate_body_ratio(day1['open'], day1['close'], day1['high'], day1['low'])\\\\n\\\\n    if day1_change >= -3 or day1_body_ratio <= 0.7:  # 跌幅>3%意味着<-3%\\\\n        return False\\\\n\\\\n    # 第2天：小K线\\\\n    day2_change = abs((day2['close'] - day2['open']) / day2['open'] * 100)\\\\n    if day2_change >= 1.5:\\\\n        return False\\\\n\\\\n    # 第3天：大阳线\\\\n    day3_change = (day3['close'] - day3['open']) / day3['open'] * 100\\\\n    day3_body_ratio = calculate_body_ratio(day3['open'], day3['close'], day3['high'], day3['low'])\\\\n\\\\n    if day3_change <= 3 or day3_body_ratio <= 0.7:\\\\n        return False\\\\n\\\\n    # 第3天收盘价高于第1天实体中点\\\\n    day1_midpoint = (day1['open'] + day1['close']) / 2\\\\n    if day3['close'] <= day1_midpoint:\\\\n        return False\\\\n\\\\n    return True\\\\n\\\\ndef check_low_position(df, i):\\\\n    \\\\\\\"\\\\\\\"\\\\\\\"\\\\n    检查低位要求：形态出现时当前价格低于60日均价的90%\\\\n    \\\\\\\"\\\\\\\"\\\\\\\"\\\\n    if i < 60:\\\\n        return False\\\\n\\\\n    # 计算60日均价（使用形态第1天之前的60天）\\\\n    ma60_data = df.iloc[i-60:i]\\\\n    ma60 = ma60_data['close'].mean()\\\\n\\\\n    # 形态第1天的收盘价\\\\n    current_price = df.iloc[i]['close']\\\\n\\\\n    return current_price < ma60 * 0.9\\\\n\\\\ndef check_follow_up(df, i):\\\\n    \\\\\\\"\\\\\\\"\\\\\\\"\\\\n    验证后续5个交易日内，价格未跌破形态的最低价\\\\n    返回 (是否通过验证, 5日后涨幅)\\\\n    \\\\\\\"\\\\\\\"\\\\\\\"\\\\n    if i + 2 + 5 >= len(df):\\\\n        return False, None\\\\n\\\\n    # 形态的最低价（3天中的最低价）\\\\n    pattern_low = min(df.iloc[i]['low'], df.iloc[i+1]['low'], df.iloc[i+2]['low'])\\\\n\\\\n    # 检查后5个交易日\\\\n    for j in range(i + 3, i + 8):\\\\n        if df.iloc[j]['low'] < pattern_low:\\\\n            return False, None\\\\n\\\\n    # 计算形态后5日涨幅（第8天相对第3天的涨幅）\\\\n    day3_close = df.iloc[i + 2]['close']\\\\n    day8_close = df.iloc[i + 7]['close']\\\\n    gain = (day8_close - day3_close) / day3_close * 100\\\\n\\\\n    return True, gain\\\\n\\\\ndef detect_morning_star(stock_code):\\\\n    \\\\\\\"\\\\\\\"\\\\\\\"检测单只股票的早晨之星形态\\\\\\\"\\\\\\\"\\\\\\\"\\\\n    df = get_stock_data(stock_code, days=90)\\\\n    if df is None or len(df) < 68:  # 至少需要60+3+5天\\\\n        return []\\\\n\\\\n    results = []\\\\n\\\\n    # 只检查最近30个交易日\\\\n    start_idx = max(60, len(df) - 30 - 7)  # 确保有60日均线和后续5日\\\\n    end_idx = len(df) - 7  # 确保有后续5日\\\\n\\\\n    for i in range(start_idx, end_idx):\\\\n        # 检查早晨之星形态\\\\n        if not check_morning_star(df, i):\\\\n            continue\\\\n\\\\n        # 检查低位要求\\\\n        if not check_low_position(df, i):\\\\n            continue\\\\n\\\\n        # 检查后续验证\\\\n        passed, gain = check_follow_up(df, i)\\\\n        if not passed:\\\\n            continue\\\\n\\\\n        # 记录结果\\\\n        pattern_date = df.iloc[i]['date'].strftime('%Y-%m-%d')\\\\n        results.append({\\\\n            'code': stock_code,\\\\n            'date': pattern_date,\\\\n            'gain': round(gain, 1)\\\\n        })\\\\n\\\\n    return results\\\\n\\\\ndef main():\\\\n    print(\\\\\\\"开始检测早晨之星形态...\\\\\\\")\\\\n\\\\n    # 获取创业板股票列表\\\\n    stocks = get_chinext_stocks()\\\\n    print(f\\\\\\\"获取到 {len(stocks)} 只创业板股票\\\\\\\")\\\\n\\\\n    all_results = []\\\\n\\\\n    # 遍历每只股票\\\\n    for idx, stock_code in enumerate(stocks):\\\\n        if idx % 50 == 0:\\\\n            print(f\\\\\\\"进度: {idx}/{len(stocks)}\\\\\\\")\\\\n\\\\n        try:\\\\n            results = detect_morning_star(stock_code)\\\\n            all_results.extend(results)\\\\n            time.sleep(0.1)  # 避免请求过快\\\\n        except Exception as e:\\\\n            print(f\\\\\\\"处理股票 {stock_code} 时出错: {e}\\\\\\\")\\\\n            continue\\\\n\\\\n    # 写入结果\\\\n    with open('morning_star.txt', 'w', encoding='utf-8') as f:\\\\n        if len(all_results) == 0:\\\\n            f.write(\\\\\\\"无符合条件的股票\\\\\\\\n\\\\\\\")\\\\n        else:\\\\n            f.write(\\\\\\\"股票代码,形态起始日期,形态后5日涨幅(%)\\\\\\\\n\\\\\\\")\\\\n            for result in all_results:\\\\n                f.write(f\\\\\\\"{result['code']},{result['date']},{result['gain']}\\\\\\\\n\\\\\\\")\\\\n\\\\n    print(f\\\\\\\"\\\\\\\\n检测完成！共找到 {len(all_results)} 个符合条件的形态\\\\\\\")\\\\n    print(\\\\\\\"结果已写入 morning_star.txt\\\\\\\")\\\\n\\\\nif __name__ == \\\\\\\"__main__\\\\\\\":\\\\n    main()\\\\n\\\",\\\"structuredPatch\\\":[{\\\"oldStart\\\":6,\\\"oldLines\\\":7,\\\"newStart\\\":6,\\\"newLines\\\":14,\\\"lines\\\":[\\\" import pandas as pd\\\",\\\" from datetime import datetime, timedelta\\\",\\\" import time\\\",\\\"+import os\\\",\\\" \\\",\\\"+# 禁用代理\\\",\\\"+os.environ['HTTP_PROXY'] = ''\\\",\\\"+os.environ['HTTPS_PROXY'] = ''\\\",\\\"+os.environ['http_proxy'] = ''\\\",\\\"+os.environ['https_proxy'] = ''\\\",\\\"+\\\",\\\" def get_chinext_stocks():\\\",\\\"     \\\\\\\"\\\\\\\"\\\\\\\"获取创业板股票列表\\\\\\\"\\\\\\\"\\\\\\\"\\\",\\\"     try:\\\"]}],\\\"userModified\\\":false,\\\"replaceAll\\\":false}}\\n/Users/tomato/Documents/potato/project/YFD/results/agent_task_with_memory/openclaw/task_21_morning_star/analyze.py:7:from mootdx.quotes import Quotes\\n/Users/tomato/Documents/potato/project/YFD/results/agent_task_with_memory/openclaw/task_17_fund_flow_obv/analyze.py:8:from mootdx.quotes import Quotes\\n\",\"exit_code\":0,\"status\":\"completed\"}}\n{\"type\":\"item.completed\",\"item\":{\"id\":\"item_7\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc \\\"python - <<'PY'\\nimport importlib\\nmods=['mootdx','akshare','pandas','numpy']\\nfor m in mods:\\n    try:\\n        mod=importlib.import_module(m)\\n        print