 '隔膜', '电解液', '光能']\n    # 半导体相关关键词\n    semi_keywords = ['半导体', '芯片', '集成电路', '晶圆', 'IC', '微电子', '存储',\n                    '射频', 'FPGA', '传感器', '电子设计', '封测', '光刻', '材料科技',\n                    '微', '纳', '导体', '电子科技', '信科', '晶', '硅', '锗']\n    # 消费电子相关关键词\n    consumer_keywords = ['消费电子', '手机', '耳机', '穿戴', '智能终端', '平板',\n                        '智能家居', '音响', '游戏', '相机', '摄像', '显示', '触控',\n                        '连接器', '天线', '电声', '声学']\n\n    name_str = str(name)\n\n    for kw in pharma_keywords:\n        if kw in name_str:\n            return '医药'\n    for kw in energy_keywords:\n        if kw in name_str:\n            return '新能源'\n    for kw in semi_keywords:\n        if kw in name_str:\n            return '半导体'\n    for kw in consumer_keywords:\n        if kw in name_str:\n            return '消费电子'\n\n    return None\n\ndef get_stock_history(code, days=70):\n    \"\"\"获取股票历史数据\"\"\"\n    try:\n        # 创业板股票在深圳市场\n        df = client.bars(symbol=code, frequency=9, offset=days)\n        if df is None or len(df) < 30:\n            return None\n        return df\n    except Exception as e:\n        return None\n\ndef calculate_returns_20d(df):\n    \"\"\"计算近20日涨幅\"\"\"\n    if df is None or len(df) < 21:\n        return None\n    close = df['close'].values\n    return (close[-1] / close[-21] - 1) * 100\n\ndef calculate_ma(df):\n    \"\"\"计算均线\"\"\"\n    if df is None or len(df) < 60:\n        return None, None\n    close = df['close'].values\n    ma20 = np.mean(close[-20:])\n    ma60 = np.mean(close[-60:])\n    return ma20, ma60\n\ndef calculate_macd(df):\n    \"\"\"计算MACD\"\"\"\n    if df is None or len(df) < 35:\n        return None\n\n    close = pd.Series(df['close'].values)\n    ema12 = close.ewm(span=12, adjust=False).mean()\n    ema26 = close.ewm(span=26, adjust=False).mean()\n    dif = ema12 - ema26\n    dea = dif.ewm(span=9, adjust=False).mean()\n    macd = (dif - dea) * 2\n\n    return macd.values\n\ndef calculate_rsi(df, period=14):\n    \"\"\"计算RSI\"\"\"\n    if df is None or len(df) < period + 5:\n        return None\n\n    close = pd.Series(df['close'].values)\n    delta = close.diff()\n    gain = (delta.where(delta > 0, 0)).rolling(window=period).mean()\n    loss = (-delta.where(delta < 0, 0)).rolling(window=period).mean()\n\n    rs = gain / loss\n    rsi = 100 - (100 / (1 + rs))\n\n    return float(rsi.iloc[-1])\n\ndef check_bullish_candles(df, days=10):\n    \"\"\"检查近N日阳线数量\"\"\"\n    if df is None or len(df) < days:\n        return 0\n\n    recent = df.tail(days)\n    bullish = (recent['close'] > recent['open']).sum()\n    return int(bullish)\n\ndef calculate_volume_ratio(df):\n    \"\"\"计算近10日成交量均值/60日成交量均值\"\"\"\n    if df is None or len(df) < 60:\n        return None\n\n    vol = df['volume'].values\n    vol10 = np.mean(vol[-10:])\n    vol60 = np.mean(vol[-60:])\n\n    if vol60 == 0:\n        return None\n    return vol10 / vol60\n\ndef get_pe_ratio(code):\n    \"\"\"获取PE比率 - 使用实时行情\"\"\"\n    try:\n        # 尝试获取实时数据中的PE\n        quote = client.quote(symbol=code)\n        if quote is not None and len(quote) > 0:\n            # mootdx实时数据可能不包含PE，尝试从其他字段推算\n            pass\n    except:\n        pass\n\n    # 使用akshare获取PE数据\n    try:\n        import akshare as ak\n        # 尝试获取创业板PE数据\n        df = ak.stock_zh_a_spot_em()\n        if df is not None:\n            stock_row = df[df['代码'] == code]\n            if len(stock_row) > 0:\n                pe = stock_row['市盈率-动态'].values[0]\n                if pe and str(pe) not in ['-', 'nan', 'None', '']:\n                    return float(pe)\n    except Exception as e:\n        pass\n\n    return None\n\ndef calculate_composite_score(stock_ret, industry_ret, rsi, bullish_days, vol_ratio, pe):\n    \"\"\"\n    设计综合评分模型\n    各维度权重：\n    - 行业趋势强度: 15%\n    - 个股超越行业程度: 25%\n    - 技术指标: 30% (RSI 15%, 均线位置已是筛选条件, MACD已是筛选条件)\n    - 量能质量: 20% (阳线10% + 量能比10%)\n    - 基本面PE: 10%\n    \"\"\"\n    score = 0.0\n\n    # 维度1: 行业趋势强度 (15分)\n    # 行业涨幅越高越好，以5%为基准，最高给15分\n    industry_score = min(15, (industry_ret - 5) / 5 * 15 + 5)\n    score += industry_score\n\n    # 维度2: 个股超越行业程度 (25分)\n    # 超越倍数越高越好，基准1.3倍，最高给25分\n    if industry_ret > 0:\n        exceed_ratio = stock_ret / industry_ret\n        exceed_score = min(25, (exceed_ratio - 1.3) / 1.0 * 15 + 10)\n    else:\n        exceed_score = 0\n    score += max(0, exceed_score)\n\n    # 维度3: RSI评分 (15分)\n    # RSI在50-70最佳，越接近60分越高\n    rsi_dist = abs(rsi - 60) / 10  # 距离60的相对距离\n    rsi_score = 15 * (1 - rsi_dist)\n    score += max(0, rsi_score)\n\n    # 维度4a: 阳线质量 (10分)\n    # 10天中阳线越多越好，6天为基准\n    bullish_score = min(10, (bullish_days - 6) / 4 * 10 + 6)\n    score += max(0, bullish_score)\n\n    # 维度4b: 量能比 (10分)\n    # 量能比越高越好，1.0为基准\n    if vol_ratio is not None:\n        vol_score = min(10, (vol_ratio - 1.0) / 1.0 * 10 + 5)\n        score += max(0, vol_score)\n\n    # 维度5: PE评分 (10分)\n    # PE越低越好，但要大于0，理想区间20-60\n    if pe is not None and pe > 0:\n        if pe < 20:\n            pe_score = 8  # 低估值\n        elif pe <= 60:\n            pe_score = 10 - (pe - 20) / 40 * 5  # 合理估值\n        else:\n            pe_score = 5 - (pe - 60) / 40 * 5  # 较高估值但<100\n        score += max(0, pe_score)\n\n    # MACD和均线是筛选条件（已满足），给予额外基础分15分\n    score += 15  # 基础技术分\n\n    return round(min(100, score), 1)\n\n\ndef main():\n    print(\"开始获取创业板股票列表...\")\n\n    # 先尝试用akshare获取所有创业板股票和PE数据\n    pe_data = {}\n    all_stocks_info = {}\n\n    try:\n        import akshare as ak\n        print(\"使用akshare获取股票数据...\")\n        df_spot = ak.stock_zh_a_spot_em()\n        if df_spot is not None:\n            # 筛选创业板\n            chinext_mask = df_spot['代码'].str.startswith('300') | df_spot['代码'].str.startswith('301')\n            chinext_df = df_spot[chinext_mask].copy()\n            print(f\"从akshare获取到 {len(chinext_df)} 只创业板股票\")\n\n            for _, row in chinext_df.iterrows():\n                code = str(row['代码'])\n                name = str(row['名称'])\n                pe = row.get('市盈率-动态', None)\n                all_stocks_info[code] = {'name': name}\n                try:\n                    if pe and str(pe) not in ['-', 'nan', 'None', '']:\n                        pe_val = float(pe)\n                        if pe_val > 0:\n                            pe_data[code] = pe_val\n                except:\n                    pass\n\n        print(f\"获取到PE数据: {len(pe_data)} 只股票\")\n    except Exception as e:\n        print(f\"akshare获取失败: {e}\")\n\n    # 构建股票列表\n    stocks_list = []\n    for code, info in all_stocks_info.items():\n        stocks_list.append({'code': code, 'name': info['name']})\n\n    if not stocks_list:\n        # 如果akshare失败，用mootdx\n        print(\"使用mootdx获取股票列表...\")\n        stocks_raw = client.stocks(market=0)\n        if stocks_raw is not None:\n            for _, row in stocks_raw.iterrows():\n                code = str(row.get('code', '')).strip()\n                if code.startswith('300') or code.startswith('301'):\n                    stocks_list.append({\n                        'code': code,\n                        'name': row.get('name', '').strip()\n                    })\n\n    print(f\"总共获取到 {len(stocks_list)} 只创业板股票\")\n\n    # 行业分类\n    industry_stocks = {\n        '医药': [],\n        '新能源': [],\n        '半导体': [],\n        '消费电子': []\n    }\n\n    for stock in stocks_list:\n        industry = classify_industry(stock['code'], stock['name'])\n        if industry:\n            industry_stocks[industry].append(stock)\n\n    for ind, stocks in industry_stocks.items():\n        print(f\"{ind}: {len(stocks)} 只股票\")\n\n    # 计算各行业近20日等权涨幅\n    print(\"\\n计算各行业等权涨幅...\")\n    industry_returns = {}\n    industry_stock_returns = {}  # 存储每只股票的涨幅\n\n    for industry, stocks in industry_stocks.items():\n        returns = []\n        stock_ret_map = {}\n\n        sample_stocks = stocks  # 处理所有股票\n        print(f\"处理{industry}行业，共{len(sample_stocks)}只股票...\")\n\n        for i, stock in enumerate(sample_stocks):\n            if i % 50 == 0:\n                print(f\"  处理第{i}/{len(sample_stocks)}只: {stock['code']}\")\n\n            df = get_stock_history(stock['code'], days=70)\n            if df is not None and len(df) >= 25:\n                ret = calculate_returns_20d(df)\n                if ret is not None and not np.isnan(ret):\n                    returns.append(ret)\n                    stock_ret_map[stock['code']] = ret\n\n        if returns:\n            avg_return = np.mean(returns)\n            industry_returns[industry] = avg_return\n            industry_stock_returns[industry] = stock_ret_map\n            print(f\"  {industry}行业近20日等权涨幅: {avg_return:.2f}%\")\n        else:\n            industry_returns[industry] = 0\n            industry_stock_returns[industry] = {}\n\n    # 找出涨幅>5%的强势行业\n    strong_industries = {k: v for k, v in industry_returns.items() if v > 5}\n    print(f\"\\n涨幅>5%的强势行业: {strong_industries}\")\n\n    if not strong_industries:\n        print(\"没有行业涨幅超过5%，输出无符合条件的股票\")\n        with open('ultimate_filter.txt', 'w', encoding='utf-8') as f:\n            f.write(\"股票代码,所属行业,行业涨幅(%),个股涨幅(%),RSI,阳线天数,量能比,PE,综合得分\\n\")\n            f.write(\"无符合条件的股票\\n\")\n        return\n\n    # 对强势行业内的每只股票进行五维度筛选\n    print(\"\\n开始五维度筛选...\")\n    qualified_stocks = []\n\n    for industry, ind_return in strong_industries.items():\n        print(f\"\\n筛选{industry}行业 (涨幅={ind_return:.2f}%)...\")\n        stocks = industry_stocks[industry]\n        stock_ret_map = industry_stock_returns[industry]\n\n        for stock in stocks:\n            code = stock['code']\n            name = stock['name']\n\n            # 获取历史数据\n            df = get_stock_history(code, days=70)\n            if df is None or len(df) < 60:\n                continue\n\n            # 维度1: 行业涨幅已满足(>5%)\n\n            # 维度2: 个股近20日涨幅 > 行业涨幅 × 1.3\n            stock_ret = stock_ret_map.get(code)\n            if stock_ret is None:\n                stock_ret = calculate_returns_20d(df)\n            if stock_ret is None:\n                continue\n\n            if stock_ret <= ind_return * 1.3:\n                continue\n\n            # 维度3a: 价格在MA20和MA60上方\n            ma20, ma60 = calculate_ma(df)\n            if ma20 is None or ma60 is None:\n                continue\n            current_price = df['close'].values[-1]\n            if current_price <= ma20 or current_price <= ma60:\n                continue\n\n            # 维度3b: MACD柱状图近5日持续为正且递增\n            macd = calculate_macd(df)\n            if macd is None or len(macd) < 5:\n                continue\n            macd_5d = macd[-5:]\n            if not all(v > 0 for v in macd_5d):\n                continue\n            # 检查递增\n            is_increasing = all(macd_5d[i] < macd_5d[i+1] for i in range(len(macd_5d)-1))\n            if not is_increasing:\n                continue\n\n            # 维度3c: RSI在50-70之间\n            rsi = calculate_rsi(df)\n            if rsi is None or not (50 <= rsi <= 70):\n                continue\n\n            # 维度4a: 近10日至少6日阳线\n            bullish_days = check_bullish_candles(df, days=10)\n            if bullish_days < 6:\n                continue\n\n            # 维度4b: 近10日成交量均值 > 60日成交量均值\n            vol_ratio = calculate_volume_ratio(df)\n            if vol_ratio is None or vol_ratio <= 1.0:\n                continue\n\n            # 维度5: PE > 0 且 PE < 100\n            pe = pe_data.get(code)\n            if pe is None:\n                pe = get_pe_ratio(code)\n            if pe is None or not (0 < pe < 100):\n                continue\n\n            # 计算综合得分\n            score = calculate_composite_score(\n                stock_ret, ind_return, rsi, bullish_days, vol_ratio, pe\n            )\n\n            qualified_stocks.append({\n                'code': code,\n                'name': name,\n                'industry': industry,\n                'ind_return': round(ind_return, 2),\n                'stock_return': round(stock_ret, 2),\n                'rsi': round(rsi, 1),\n                'bullish_days': bullish_days,\n                'vol_ratio': round(vol_ratio, 2),\n                'pe': round(pe, 1),\n                'score': score\n            })\n            print(f\"  通过筛选: {code} {name} | 行业涨幅:{ind_return:.1f}% | 个股涨幅:{stock_ret:.1f}% | RSI:{rsi:.1f} | 阳线:{bullish_days} | 量能比:{vol_ratio:.2f} | PE:{pe:.1f} | 得分:{score}\")\n\n    # 按综合得分排序\n    qualified_stocks.sort(key=lambda x: x['score'], reverse=True)\n\n    print(f\"\\n共找到 {len(qualified_stocks)} 只满足所有条件的股票\")\n\n    # 写入结果文件\n    with open('ultimate_filter.txt', 'w', encoding='utf-8') as f:\n        f.write(\"股票代码,所属行业,行业涨幅(%),个股涨幅(%),RSI,阳线天数,量能比,PE,综合得分\\n\")\n\n        if not qualified_stocks:\n            f.write(\"无符合条件的股票\\n\")\n            print(\"无符合所有条件的股票\")\n        else:\n            for s in qualified_stocks:\n                line = f\"{s['code']},{s['industry']},{s['ind_return']},{s['stock_return']},{s['rsi']},{s['bullish_days']},{s['vol_ratio']},{s['pe']},{s['score']}\"\n                f.write(line + \"\\n\")\n                print(f\"  {line}\")\n\n    print(f\"\\n结果已写入 ultimate_filter.txt\")\n    print(f\"强势行业: {strong_industries}\")\n    print(f\"MACD, RSI, MA20, MA60, 均线, 量能比 均已计算\")\n    print(f\"PE基本面条件已检查\")\n\n\nif __name__ == '__main__':\n    main()\n"},"name":"Write","type":"tool_use"}],"id":"req_vrtx_011CZpHJyQMPjjg8PbPeQYJY","model":"claude-sonnet-4-6","role":"assistant","stop_reason":null,"stop_sequence":null,"type":"message","usage":{"input_tokens":3649,"output_tokens":2,"cache_read_input_tokens":24418},"context_management":null},"parent_tool_use_id":null,"session_id":"130141ef-94ad-4bcd-b648-1b10ef40f248","uuid":"027f1c57-4326-456e-8465-4128a64d8f36"}
/Users/tomato/Documents/potato/project/YFD/results/agent_task_v1/claude_sonnet/task_20_ultimate_multi_condition/trajectory/stdout.txt:78:{"type":"user","message":{"role":"user","content":[{"tool_use_id":"toolu_vrtx_01TVNKP3CVbndnGFjaE2CUbj","type":"tool_result","content":"File created successfully at: /Users/tomato/Documents/potato/project/YFD/results/agent_task/claude/task_20_ultimate_multi_condition/analyze.py"}]},"parent_tool_use_id":null,"session_id":"130141ef-94ad-4bcd-b648-1b10ef40f248","uuid":"9bd6afd6-add2-4d45-b94b-3b894b31b7de","timestamp":"2026-04-07T10:51:45.113Z","tool_use_result":{"type":"create","filePath":"/Users/tomato/Documents/potato/project/YFD/results/agent_task/claude/task_20_ultimate_multi_condition/analyze.py","content":"#!/usr/bin/env python3\n\"\"\"\n五维度综合评分超级选股 - 创业板股票筛选\n\"\"\"\n\nimport pandas as pd\nimport numpy as np\nfrom mootdx.quotes import Quotes\nimport warnings\nwarnings.filterwarnings('ignore')\n\n# 初始化客户端\nclient = Quotes.factory(market='std')\n\ndef get_all_chinext_stocks():\n    \"\"\"获取所有创业板股票\"\"\"\n    stocks = client.stocks(market=0)  # 深圳市场\n    if stocks is None or len(stocks) == 0:\n        stocks = client.stocks(market=1)\n\n    # 创业板股票代码以300或301开头\n    chinext = []\n    if stocks is not None:\n        for _, row in stocks.iterrows():\n            code = str(row.get('code', '')).strip()\n            if code.startswith('300') or code.startswith('301'):\n                chinext.append({\n                    'code': code,\n                    'name': row.get('name', '').strip()\n                })\n\n    return chinext\n\ndef classify_industry(code, name):\n    \"\"\"根据股票代码和名称进行行业分类\"\"\"\n    # 医药相关关键词\n    pharma_keywords = ['医药', '医疗', '生物', '制药', '药业', '健康', '医院', '诊断',\n                       '基因', '疫苗', '血液', '骨科', '眼科', '口腔', '心脑', '肿瘤',\n                       '康', '药', '医', '生命科技', '生命', '细胞', '蛋白', '抗体']\n    # 新能源相关关键词\n    energy_keywords = ['新能源', '光伏', '风电', '储能', '锂电', '电池', '充电', '太阳能',\n                      '氢能', '燃料电池', '特高压', '电力', '能源', '绿色', '碳', '阳光',\n                      '锂', '钠', '钒', '正极', '负极', '隔膜', '电解液', '光能']\n    # 半导体相关关键词\n    semi_keywords = ['半导体', '芯片', '集成电路', '晶圆', 'IC', '微电子', '存储',\n                    '射频', 'FPGA', '传感器', '电子设计', '封测', '光刻', '材料科技',\n                    '微', '纳', '导体', '电子科技', '信科', '晶', '硅', '锗']\n    # 消费电子相关关键词\n    consumer_keywords = ['消费电子', '手机', '耳机', '穿戴', '智能终端', '平板',\n                        '智能家居', '音响', '游戏', '相机', '摄像', '显示', '触控',\n                        '连接器', '天线', '电声', '声学']\n\n    name_str = str(name)\n\n    for kw in pharma_keywords:\n        if kw in name_str:\n            return '医药'\n    for kw in energy_keywords:\n        if kw in name_str:\n            return '新能源'\n    for kw in semi_keywords:\n        if kw in name_str:\n            return '半导体'\n    for kw in consumer_keywords:\n        if kw in name_str:\n            return '消费电子'\n\n    return None\n\ndef get_stock_history(code, days=70):\n    \"\"\"获取股票历史数据\"\"\"\n    try:\n        # 创业板股票在深圳市场\n        df = client.bars(symbol=code, frequency=9, offset=days)\n        if df is None or len(df) < 30:\n            return None\n        return df\n    except Exception as e:\n        return None\n\ndef calculate_returns_20d(df):\n    \"\"\"计算近20日涨幅\"\"\"\n    if df is None or len(df) < 21:\n        return None\n    close = df['close'].values\n    return (close[-1] / close[-21] - 1) * 100\n\ndef calculate_ma(df):\n    \"\"\"计算均线\"\"\"\n    if df is None or len(df) < 60:\n        return None, None\n    close = df['close'].values\n    ma20 = np.mean(close[-20:])\n    ma60 = np.mean(close[-60:])\n    return ma20, ma60\n\ndef calculate_macd(df):\n    \"\"\"计算MACD\"\"\"\n    if df is None or len(df) < 35:\n        return None\n\n    close = pd.Series(df['close'].values)\n    ema12 = close.ewm(span=12, adjust=False).mean()\n    ema26 = close.ewm(span=26, adjust=False).mean()\n    dif = ema12 - ema26\n    dea = dif.ewm(span=9, adjust=False).mean()\n    macd = (dif - dea) * 2\n\n    return macd.values\n\ndef calculate_rsi(df, period=14):\n    \"\"\"计算RSI\"\"\"\n    if df is None or len(df) < period + 5:\n        return None\n\n    close = pd.Series(df['close'].values)\n    delta = close.diff()\n    gain = (delta.where(delta > 0, 0)).rolling(window=period).mean()\n    loss = (-delta.where(delta < 0, 0)).rolling(window=period).mean()\n\n    rs = gain / loss\n    rsi = 100 - (100 / (1 + rs))\n\n    return float(rsi.iloc[-1])\n\ndef check_bullish_candles(df, days=10):\n    \"\"\"检查近N日阳线数量\"\"\"\n    if df is None or len(df) < days:\n        return 0\n\n    recent = df.tail(days)\n    bullish = (recent['close'] > recent['open']).sum()\n    return int(bullish)\n\ndef calculate_volume_ratio(df):\n    \"\"\"计算近10日成交量均值/60日成交量均值\"\"\"\n    if df is None or len(df) < 60:\n        return None\n\n    vol = df['volume'].values\n    vol10 = np.mean(vol[-10:])\n    vol60 = np.mean(vol[-60:])\n\n    if vol60 == 0:\n        return None\n    return vol10 / vol60\n\ndef get_pe_ratio(code):\n    \"\"\"获取PE比率 - 使用实时行情\"\"\"\n    try:\n        # 尝试获取实时数据中的PE\n        quote = client.quote(symbol=code)\n        if quote is not None and len(quote) > 0:\n            # mootdx实时数据可能不包含PE，尝试从其他字段推算\n            pass\n    except:\n        pass\n\n    # 使用akshare获取PE数据\n    try:\n        import akshare as ak\n        # 尝试获取创业板PE数据\n        df = ak.stock_zh_a_spot_em()\n        if df is not None:\n            stock_row = df[df['代码'] == code]\n            if len(stock_row) > 0:\n                pe = stock_row['市盈率-动态'].values[0]\n                if pe and str(pe) not in ['-', 'nan', 'None', '']:\n                    return float(pe)\n    except Exception as e:\n        pass\n\n    return None\n\ndef calculate_composite_score(stock_ret, industry_ret, rsi, bullish_days, vol_ratio, pe):\n    \"\"\"\n    设计综合评分模型\n    各维度权重：\n    - 行业趋势强度: 15%\n    - 个股超越行业程度: 25%\n    - 技术指标: 30% (RSI 15%, 均线位置已是筛选条件, MACD已是筛选条件)\n    - 量能质量: 20% (阳线10% + 量能比10%)\n    - 基本面PE: 10%\n    \"\"\"\n    score = 0.0\n\n    # 维度1: 行业趋势强度 (15分)\n    # 行业涨幅越高越好，以5%为基准，最高给15分\n    industry_score = min(15, (industry_ret - 5) / 5 * 15 + 5)\n    score += industry_score\n\n    # 维度2: 个股超越行业程度 (25分)\n    # 超越倍数越高越好，基准1.3倍，最高给25分\n    if industry_ret > 0:\n        exceed_ratio = stock_ret / industry_ret\n        exceed_score = min(25, (exceed_ratio - 1.3) / 1.0 * 15 + 10)\n    else:\n        exceed_score = 0\n    score += max(0, exceed_score)\n\n    # 维度3: RSI评分 (15分)\n    # RSI在50-70最佳，越接近60分越高\n    rsi_dist = abs(rsi - 60) / 10  # 距离60的相对距离\n    rsi_score = 15 * (1 - rsi_dist)\n    score += max(0, rsi_score)\n\n    # 维度4a: 阳线质量 (10分)\n    # 10天中阳线越多越好，6天为基准\n    bullish_score = min(10, (bullish_days - 6) / 4 * 10 + 6)\n    score += max(0, bullish_score)\n\n    # 维度4b: 量能比 (10分)\n    # 量能比越高越好，1.0为基准\n    if vol_ratio is not None:\n        vol_score = min(10, (vol_ratio - 1.0) / 1.0 * 10 + 5)\n        score += max(0, vol_score)\n\n    # 维度5: PE评分 (10分)\n    # PE越低越好，但要大于0，理想区间20-60\n    if pe is not None and pe > 0:\n        if pe < 20:\n            pe_score = 8  # 低估值\n        elif pe <= 60:\n            pe_score = 10 - (pe - 20) / 40 * 5  # 合理估值\n        else:\n            pe_score = 5 - (pe - 60) / 40 * 5  # 较高估值但<100\n        score += max(0, pe_score)\n\n    # MACD和均线是筛选条件（已满足），给予额外基础分15分\n    score += 15  # 基础技术分\n\n    return round(min(100, score), 1)\n\n\ndef main():\n    print(\"开始获取创业板股票列表...\")\n\n    # 先尝试用akshare获取所有创业板股票和PE数据\n    pe_data = {}\n    all_stocks_info = {}\n\n    try:\n        import akshare as ak\n        print(\"使用akshare获取股票数据...\")\n        df_spot = ak.stock_zh_a_spot_em()\n        if df_spot is not None:\n            # 筛选创业板\n            chinext_mask = df_spot['代码'].str.startswith('300') | df_spot['代码'].str.startswith('301')\n            chinext_df = df_spot[chinext_mask].copy()\n            print(f\"从akshare获取到 {len(chinext_df)} 只创业板股票\")\n\n            for _, row in chinext_df.iterrows():\n                code = str(row['代码'])\n                name = str(row['名称'])\n                pe = row.get('市盈率-动态', None)\n                all_stocks_info[code] = {'name': name}\n                try:\n                    if pe and str(pe) not in ['-', 'nan', 'None', '']:\n                        pe_val = float(pe)\n                        if pe_val > 0:\n                            pe_data[code] = pe_val\n                except:\n                    pass\n\n        print(f\"获取到PE数据: {len(pe_data)} 只股票\")\n    except Exception as e:\n        print(f\"akshare获取失败: {e}\")\n\n    # 构建股票列表\n    stocks_list = []\n    for code, info in all_stocks_info.items():\n        stocks_list.append({'code': code, 'name': info['name']})\n\n    if not stocks_list:\n        # 如果akshare失败，用mootdx\n        print(\"使用mootdx获取股票列表...\")\n        stocks_raw = client.stocks(market=0)\n        if stocks_raw is not None:\n            for _, row in stocks_raw.iterrows():\n                code = str(row.get('code', '')).strip()\n                if code.startswith('300') or code.startswith('301'):\n                    stocks_list.append({\n                        'code': code,\n                        'name': row.get('name', '').strip()\n                    })\n\n    print(f\"总共获取到 {len(stocks_list)} 只创业板股票\")\n\n    # 行业分类\n    industry_stocks = {\n        '医药': [],\n        '新能源': [],\n        '半导体': [],\n        '消费电子': []\n    }\n\n    for stock in stocks_list:\n        industry = classify_industry(stock['code'], stock['name'])\n        if industry:\n            industry_stocks[industry].append(stock)\n\n    for ind, stocks in industry_stocks.items():\n        print(f\"{ind}: {len(stocks)} 只股票\")\n\n    # 计算各行业近20日等权涨幅\n    print(\"\\n计算各行业等权涨幅...\")\n    industry_returns = {}\n    industry_stock_returns = {}  # 存储每只股票的涨幅\n\n    for industry, stocks in industry_stocks.items():\n        returns = []\n        stock_ret_map = {}\n\n        sample_stocks = stocks  # 处理所有股票\n        print(f\"处理{industry}行业，共{len(sample_stocks)}只股票...\")\n\n        for i, stock in enumerate(sample_stocks):\n            if i % 50 == 0:\n                print(f\"  处理第{i}/{len(sample_stocks)}只: {stock['code']}\")\n\n            df = get_stock_history(stock['code'], days=70)\n            if df is not None and len(df) >= 25:\n                ret = calculate_returns_20d(df)\n                if ret is not None and not np.isnan(ret):\n                    returns.append(ret)\n                    stock_ret_map[stock['code']] = ret\n\n        if returns:\n            avg_return = np.mean(returns)\n            industry_returns[industry] = avg_return\n            industry_stock_returns[industry] = stock_ret_map\n            print(f\"  {industry}行业近20日等权涨幅: {avg_return:.2f}%\")\n        else:\n            industry_returns[industry] = 0\n            industry_stock_returns[industry] = {}\n\n    # 找出涨幅>5%的强势行业\n    strong_industries = {k: v for k, v in industry_returns.items() if v > 5}\n    print(f\"\\n涨幅>5%的强势行业: {strong_industries}\")\n\n    if not strong_industries:\n        print(\"没有行业涨幅超过5%，输出无符合条件的股票\")\n        with open('ultimate_filter.txt', 'w', encoding='utf-8') as f:\n            f.write(\"股票代码,所属行业,行业涨幅(%),个股涨幅(%),RSI,阳线天数,量能比,PE,综合得分\\n\")\n            f.write(\"无符合条件的股票\\n\")\n        return\n\n    # 对强势行业内的每只股票进行五维度筛选\n    print(\"\\n开始五维度筛选...\")\n    qualified_stocks = []\n\n    for industry, ind_return in strong_industries.items():\n        print(f\"\\n筛选{industry}行业 (涨幅={ind_return:.2f}%)...\")\n        stocks = industry_stocks[industry]\n        stock_ret_map = industry_stock_returns[industry]\n\n        for stock in stocks:\n            code = stock['code']\n            name = stock['name']\n\n            # 获取历史数据\n            df = get_stock_history(code, days=70)\n            if df is None or len(df) < 60:\n                continue\n\n            # 维度1: 行业涨幅已满足(>5%)\n\n            # 维度2: 个股近20日涨幅 > 行业涨幅 × 1.3\n            stock_ret = stock_ret_map.get(code)\n            if stock_ret is None:\n                stock_ret = calculate_returns_20d(df)\n            if stock_ret is None:\n                continue\n\n            if stock_ret <= ind_return * 1.3:\n                continue\n\n            # 维度3a: 价格在MA20和MA60上方\n            ma20, ma60 = calculate_ma(df)\n            if ma20 is None or ma60 is None:\n                continue\n            current_price = df['close'].values[-1]\n            if current_price <= ma20 or current_price <= ma60:\n                continue\n\n            # 维度3b: MACD柱状图近5日持续为正且递增\n            macd = calculate_macd(df)\n            if macd is None or len(macd) < 5:\n                continue\n            macd_5d = macd[-5:]\n            if not all(v > 0 for v in macd_5d):\n                continue\n            # 检查递增\n            is_increasing = all(macd_5d[i] < macd_5d[i+1] for i in range(len(macd_5d)-1))\n            if not is_increasing:\n                continue\n\n            # 维度3c: RSI在50-70之间\n            rsi = calculate_rsi(df)\n            if rsi is None or not (50 <= rsi <= 70):\n                continue\n\n            # 维度4a: 近10日至少6日阳线\n            bullish_days = check_bullish_candles(df, days=10)\n            if bullish_days < 6:\n                continue\n\n            # 维度4b: 近10日成交量均值 > 60日成交量均值\n            vol_ratio = calculate_volume_ratio(df)\n            if vol_ratio is None or vol_ratio <= 1.0:\n                continue\n\n            # 维度5: PE > 0 且 PE < 100\n            pe = pe_data.get(code)\n            if pe is None:\n                pe = get_pe_ratio(code)\n            if pe is None or not (0 < pe < 100):\n                continue\n\n            # 计算综合得分\n            score = calculate_composite_score(\n                stock_ret, ind_return, rsi, bullish_days, vol_ratio, pe\n            )\n\n            qualified_stocks.append({\n                'code': code,\n                'name': name,\n                'industry': industry,\n                'ind_return': round(ind_return, 2),\n                'stock_return': round(stock_ret, 2),\n                'rsi': round(rsi, 1),\n                'bullish_days': bullish_days,\n                'vol_ratio': round(vol_ratio, 2),\n                'pe': round(pe, 1),\n                'score': score\n            })\n            print(f\"  通过筛选: {code} {name} | 行业涨幅:{ind_return:.1f}% | 个股涨幅:{stock_ret:.1f}% | RSI:{rsi:.1f} | 阳线:{bullish_days} | 量能比:{vol_ratio:.2f} | PE:{pe:.1f} | 得分:{score}\")\n\n    # 按综合得分排序\n    qualified_stocks.sort(key=lambda x: x['score'], reverse=True)\n\n    print(f\"\\n共找到 {len(qualified_stocks)} 只满足所有条件的股票\")\n\n    # 写入结果文件\n    with open('ultimate_filter.txt', 'w', encoding='utf-8') as f:\n        f.write(\"股票代码,所属行业,行业涨幅(%),个股涨幅(%),RSI,阳线天数,量能比,PE,综合得分\\n\")\n\n        if not qualified_stocks:\n            f.write(\"无符合条件的股票\\n\")\n            print(\"无符合所有条件的股票\")\n        else:\n            for s in qualified_stocks:\n                line = f\"{s['code']},{s['industry']},{s['ind_return']},{s['stock_return']},{s['rsi']},{s['bullish_days']},{s['vol_ratio']},{s['pe']},{s['score']}\"\n                f.write(line + \"\\n\")\n                print(f\"  {line}\")\n\n    print(f\"\\n结果已写入 ultimate_filter.txt\")\n    print(f\"强势行业: {strong_industries}\")\n    print(f\"MACD, RSI, MA20, MA60, 均线, 量能比 均已计算\")\n    print(f\"PE基本面条件已检查\")\n\n\nif __name__ == '__main__':\n    main()\n","structuredPatch":[],"originalFile":null}}
