/Users/tomato/Documents/potato/project/YFD/results/agent_task_v1/claude_sonnet/task_20_ultimate_multi_condition/trajectory/stdout.txt:109:{"type":"stream_event","event":{"delta":{"partial_json":"{\"content\":\"#!/usr/bin/env python3\\n\\\"\\\"\\\"\\n五维度综合评分超级选股 - 创业板股票筛选\\n改进版：使用更完善的行业分类\\n\\\"\\\"\\\"\\n\\nimport pandas as pd\\nimport numpy as np\\nfrom mootdx.quotes import Quotes\\nimport warnings\\nwarnings.filterwarnings('ignore')\\n\\n# 初始化客户端\\nclient = Quotes.factory(market='std')\\n\\ndef get_all_chinext_stocks():\\n    \\\"\\\"\\\"获取所有创业板股票\\\"\\\"\\\"\\n    stocks_raw = client.stocks(market=0)\\n    chinext = []\\n    if stocks_raw is not None:\\n        for _, row in stocks_raw.iterrows():\\n            code = str(row.get('code', '')).strip()\\n            if code.startswith('300') or code.startswith('301'):\\n                chinext.append({\\n                    'code': code,\\n                    'name': row.get('name', '').strip()\\n                })\\n    return chinext\\n\\ndef classify_industry_by_sw(code, name):\\n    \\\"\\\"\\\"\\n    更广泛的行业分类 - 基于名称关键词和股票代码特征\\n    覆盖医药、新能源、半导体、消费电子四个行业\\n    \\\"\\\"\\\"\\n    name_str = str(name).upper()\\n\\n    # ======== 医药行业 ========\\n    pharma_kws = [\\n        '医药', '医疗', '生物', '制药', '药业', '健康', '医院', '诊断',\\n        '基因', '疫苗', '血液', '骨科', '眼科', '口腔', '心脑', '肿瘤',\\n        '药', '医', '细胞', '蛋白质', '抗体', '器械', '消毒', '检测',\\n        '中药', '西药', '化药', '生化', '体外', '放射', '辅助生殖',\\n        '康复', '透析', '植入', '手术', '内窥镜', '影像', '导管',\\n        '牙', '骨', '皮肤', '神经', '肿', '糖尿', '高血压'\\n    ]\\n\\n    # ======== 新能源行业 ========\\n    energy_kws = [\\n        '新能源', '光伏', '风电', '储能', '锂电', '电池', '充电', '太阳能',\\n        '氢能', '燃料电池', '特高压', '光能', '锂', '钠离子', '钒',\\n        '正极', '负极', '隔膜', '电解液', '电解质', '碳纳米',\\n        '硅碳', '磷酸铁锂', '三元材料', '电化学', '双碳',\\n        '动力电池', '储电', '逆变', '光储', '风储', '新材料',\\n        '导电', '电解槽', '质子交换膜'\\n    ]\\n\\n    # ======== 半导体行业 ========\\n    semi_kws = [\\n        '半导体', '芯片', '集成电路', '晶圆', '微电子', '存储',\\n        '射频', '传感器', '封测', '光刻', '功率', 'LED', '光电',\\n        '激光', '红外', '雷达', '导航', '定位', 'GPS', 'MEMS',\\n        '功率器件', 'IGBT', '模拟', '数模', '混合信号',\\n        '晶体管', '二极管', '三极管', '场效应', '逻辑',\\n        'IC设计', '设计', '器件', '制造', '科创'\\n    ]\\n\\n    # ======== 消费电子行业 ========\\n    consumer_kws = [\\n        '消费电子', '手机', '耳机', '穿戴', '智能终端', '平板',\\n        '智能家居', '音响', '游戏', '相机', '摄像', '显示',\\n        '触控', '连接器', '天线', '电声', '声学', '蓝牙',\\n        'TWS', '智能音箱', '可穿戴', '电视', '显示屏',\\n        '背光', '偏光', '光学', '摄像头', '镜头', 'CMOS',\\n        'VR', 'AR', '元宇宙', '机器人', '智能硬件'\\n    ]\\n\\n    # 按顺序匹配（防止交叉）- 先匹配更具体的\\n    for kw in pharma_kws:\\n        if kw in name_str:\\n            return '医药'\\n    for kw in energy_kws:\\n        if kw in name_str:\\n            return '新能源'\\n    for kw in semi_kws:\\n        if kw in name_str:\\n            return '半导体'\\n    for kw in consumer_kws:\\n        if kw in name_str:\\n            return '消费电子'\\n\\n    return None\\n\\ndef get_stock_history(code, days=70):\\n    \\\"\\\"\\\"获取股票历史数据\\\"\\\"\\\"\\n    try:\\n        df = client.bars(symbol=code, frequency=9, offset=days)\\n        if df is None or len(df) \\u003c 30:\\n            return None\\n        return df\\n    except Exception as e:\\n        return None\\n\\ndef calculate_returns_20d(df):\\n    \\\"\\\"\\\"计算近20日涨幅\\\"\\\"\\\"\\n    if df is None or len(df) \\u003c 21:\\n        return None\\n    close = df['close'].values\\n    if close[-21] == 0:\\n        return None\\n    return (close[-1] / close[-21] - 1) * 100\\n\\ndef calculate_ma(df):\\n    \\\"\\\"\\\"计算均线\\\"\\\"\\\"\\n    if df is None or len(df) \\u003c 60:\\n        return None, None\\n    close = df['close'].values\\n    ma20 = np.mean(close[-20:])\\n    ma60 = np.mean(close[-60:])\\n    return ma20, ma60\\n\\ndef calculate_macd(df):\\n    \\\"\\\"\\\"计算MACD\\\"\\\"\\\"\\n    if df is None or len(df) \\u003c 35:\\n        return None\\n\\n    close = pd.Series(df['close'].values)\\n    ema12 = close.ewm(span=12, adjust=False).mean()\\n    ema26 = close.ewm(span=26, adjust=False).mean()\\n    dif = ema12 - ema26\\n    dea = dif.ewm(span=9, adjust=False).mean()\\n    macd = (dif - dea) * 2\\n\\n    return macd.values\\n\\ndef calculate_rsi(df, period=14):\\n    \\\"\\\"\\\"计算RSI\\\"\\\"\\\"\\n    if df is None or len(df) \\u003c period + 5:\\n        return None\\n\\n    close = pd.Series(df['close'].values)\\n    delta = close.diff()\\n    gain = (delta.where(delta \\u003e 0, 0)).rolling(window=period).mean()\\n    loss = (-delta.where(delta \\u003c 0, 0)).rolling(window=period).mean()\\n\\n    rs = gain / (loss + 1e-10)\\n    rsi = 100 - (100 / (1 + rs))\\n\\n    return float(rsi.iloc[-1])\\n\\ndef check_bullish_candles(df, days=10):\\n    \\\"\\\"\\\"检查近N日阳线数量\\\"\\\"\\\"\\n    if df is None or len(df) \\u003c days:\\n        return 0\\n\\n    recent = df.tail(days)\\n    bullish = (recent['close'] \\u003e recent['open']).sum()\\n    return int(bullish)\\n\\ndef calculate_volume_ratio(df):\\n    \\\"\\\"\\\"计算近10日成交量均值/60日成交量均值\\\"\\\"\\\"\\n    if df is None or len(df) \\u003c 60:\\n        return None\\n\\n    vol = df['volume'].values\\n    vol10 = np.mean(vol[-10:])\\n    vol60 = np.mean(vol[-60:])\\n\\n    if vol60 == 0:\\n        return None\\n    return vol10 / vol60\\n\\ndef get_pe_from_mootdx(code):\\n    \\\"\\\"\\\"从mootdx获取财务数据估算PE\\\"\\\"\\\"\\n    try:\\n        # 获取实时行情\\n        quotes = client.quotes(symbol=[code])\\n        if quotes is None or len(quotes) == 0:\\n            return None\\n\\n        # 某些版本mootdx会返回PE相关字段\\n        row = quotes.iloc[0]\\n        # 尝试多个可能的字段名\\n        for field in ['pe', 'PE', 'price_earnings_ratio', 'pe_ttm']:\\n            if field in row and row[field] and str(row[field]) not in ['0', '0.0', 'nan', 'None']:\\n                return float(row[field])\\n    except:\\n        pass\\n    return None\\n\\ndef calculate_composite_score(stock_ret, industry_ret, rsi, bullish_days, vol_ratio, pe):\\n    \\\"\\\"\\\"\\n    综合评分模型 (满分100分)\\n    - 行业趋势强度: 15分\\n    - 个股超越行业程度: 25分\\n    - RSI质量: 15分\\n    - 阳线质量: 10分\\n    - 量能质量: 10分\\n    - PE估值: 10分\\n    - 技术基础分(均线+MACD已满足): 15分\\n    \\\"\\\"\\\"\\n    score = 0.0\\n\\n    # 维度1: 行业趋势强度 (15分)\\n    industry_score = min(15, max(5, (industry_ret - 5) / 5 * 10 + 5))\\n    score += industry_score\\n\\n    # 维度2: 个股超越行业程度 (25分)\\n    if industry_ret != 0:\\n        exceed_ratio = stock_ret / industry_ret if industry_ret \\u003e 0 else 0\\n        exceed_score = min(25, max(10, (exceed_ratio - 1.3) * 15 + 10))\\n    else:\\n        exceed_score = 10\\n    score += exceed_score\\n\\n    # 维度3: RSI评分 (15分) - 越接近60越好\\n    rsi_dist = abs(rsi - 60) / 10\\n    rsi_score = max(0, 15 * (1 - rsi_dist))\\n    score += rsi_score\\n\\n    # 维度4a: 阳线质量 (10分)\\n    bullish_score = min(10, max(6, (bullish_days - 6) * 2 + 6))\\n    score += bullish_score\\n\\n    # 维度4b: 量能比 (10分)\\n    if vol_ratio is not None:\\n        vol_score = min(10, max(5, (vol_ratio - 1.0) * 5 + 5))\\n        score += vol_score\\n\\n    # 维度5: PE评分 (10分) - 适中PE给高分\\n    if pe is not None and 0 \\u003c pe \\u003c 100:\\n        if 15 \\u003c= pe \\u003c= 60:\\n            pe_score = 10 - abs(pe - 35) / 25 * 5\\n        elif pe \\u003c 15:\\n            pe_score = 7  # 极低PE可能有问题\\n        else:\\n            pe_score = 10 - (pe - 60) / 40 * 10  # 60-100区间递减\\n        score += max(0, pe_score)\\n\\n    # 技术基础分 (15分) - 通过均线和MACD筛选\\n    score += 15\\n\\n    return round(min(100, max(0, score)), 1)\\n\\n\\ndef main():\\n    print(\\\"开始获取创业板股票列表...\\\")\\n\\n    # 获取股票列表\\n    stocks_list = get_all_chinext_stocks()\\n    print(f\\\"总共获取到 {len(stocks_list)} 只创业板股票\\\")\\n\\n    # 行业分类\\n    industry_stocks = {\\n        '医药': [],\\n        '新能源': [],\\n        '半导体': [],\\n        '消费电子': []\\n    }\\n\\n    for stock in stocks_list:\\n        industry = classify_industry_by_sw(stock['code'], stock['name'])\\n        if industry:\\n            industry_stocks[industry].append(stock)\\n\\n    total_classified = sum(len(v) for v in industry_stocks.values())\\n    print(f\\\"行业分类结果（共{total_classified}只）：\\\")\\n    for ind, stocks in industry_stocks.items():\\n        print(f\\\"  {ind}: {len(stocks)} 只\\\")\\n\\n    # 计算各行业近20日等权涨幅\\n    print(\\\"\\\\n计算各行业等权涨幅（MA20 vs MA60 涨幅计算）...\\\")\\n    industry_returns = {}\\n    industry_stock_returns = {}\\n\\n    for industry, stocks in industry_stocks.items():\\n        returns = []\\n        stock_ret_map = {}\\n\\n        print(f\\\"\\\\n处理{industry}行业，共{len(stocks)}只股票...\\\")\\n        for i, stock in enumerate(stocks):\\n            if i % 30 == 0 and i \\u003e 0:\\n                print(f\\\"  进度: {i}/{len(stocks)}\\\")\\n\\n            df = get_stock_history(stock['code'], days=70)\\n            if df is not None and len(df) \\u003e= 25:\\n                ret = calculate_returns_20d(df)\\n                if ret is not None and not np.isnan(ret) and abs(ret) \\u003c 200:  # 过滤异常值\\n                    returns.append(ret)\\n                    stock_ret_map[stock['code']] = ret\\n\\n        if returns:\\n            avg_return = np.mean(returns)\\n            industry_returns[industry] = avg_return\\n            industry_stock_returns[industry] = stock_ret_map\\n            print(f\\\"  {industry}行业近20日等权涨幅: {avg_return:.2f}% (样本数:{len(returns)})\\\")\\n        else:\\n            industry_returns[industry] = 0\\n            industry_stock_returns[industry] = {}\\n\\n    # 找出涨幅\\u003e5%的强势行业\\n    strong_industries = {k: v for k, v in industry_returns.items() if v \\u003e 5}\\n    print(f\\\"\\\\n所有行业涨幅：{industry_returns}\\\")\\n    print(f\\\"涨幅\\u003e5%的强势行业: {strong_industries}\\\")\\n\\n    # 写入结果文件头\\n    output_lines = [\\\"股票代码,所属行业,行业涨幅(%),个股涨幅(%),RSI,阳线天数,量能比,PE,综合得分\\\"]\\n\\n    if not strong_industries:\\n        print(\\\"没有行业涨幅超过5%，将输出无符合条件的结果\\\")\\n        # 为了完整性，用最接近条件的行业(涨幅最高)作为参考\\n        max_industry = max(industry_returns.items(), key=lambda x: x[1])\\n        print(f\\\"最高涨幅行业: {max_industry}\\\")\\n        output_lines.append(\\\"无符合条件的股票（所有目标行业近20日涨幅均未超过5%）\\\")\\n    else:\\n        # 对强势行业内的每只股票进行五维度筛选\\n        print(\\\"\\\\n开始五维度筛选...\\\")\\n        qualified_stocks = []\\n\\n        for industry, ind_return in strong_industries.items():\\n            print(f\\\"\\\\n筛选{industry}行业 (涨幅={ind_return:.2f}%)...\\\")\\n            stocks = industry_stocks[industry]\\n            stock_ret_map = industry_stock_returns[industry]\\n\\n            pass_d2 = pass_d3a = pass_d3b = pass_d3c = pass_d4a = pass_d4b = pass_d5 = 0\\n\\n            for stock in stocks:\\n                code = stock['code']\\n                name = stock['name']\\n\\n                # 获取历史数据\\n                df = get_stock_history(code, days=70)\\n                if df is None or len(df) \\u003c 60:\\n                    continue\\n\\n                # 维度2: 个股近20日涨幅 \\u003e 行业涨幅 × 1.3\\n                stock_ret = stock_ret_map.get(code)\\n                if stock_ret is None:\\n                    stock_ret = calculate_returns_20d(df)\\n                if stock_ret is None:\\n                    continue\\n\\n                if stock_ret \\u003c= ind_return * 1.3:\\n                    continue\\n                pass_d2 += 1\\n\\n                # 维度3a: 价格在MA20和MA60上方\\n                ma20, ma60 = calculate_ma(df)\\n                if ma20 is None or ma60 is None:\\n                    continue\\n                current_price = df['close'].values[-1]\\n                if current_price \\u003c= ma20 or current_price \\u003c= ma60:\\n                    continue\\n                pass_d3a += 1\\n\\n                # 维度3b: MACD柱状图近5日持续为正且递增\\n                macd = calculate_macd(df)\\n                if macd is None or len(macd) \\u003c 5:\\n                    continue\\n                macd_5d = macd[-5:]\\n                if not all(v \\u003e 0 for v in macd_5d):\\n                    continue\\n                is_increasing = all(macd_5d[i] \\u003c macd_5d[i+1] for i in range(len(macd_5d)-1))\\n                if not is_increasing:\\n                    continue\\n                pass_d3b += 1\\n\\n                # 维度3c: RSI在50-70之间\\n                rsi = calculate_rsi(df)\\n                if rsi is None or not (50 \\u003c= rsi \\u003c= 70):\\n                    continue\\n                pass_d3c += 1\\n\\n                # 维度4a: 近10日至少6日阳线\\n                bullish_days_count = check_bullish_candles(df, days=10)\\n                if bullish_days_count \\u003c 6:\\n                    continue\\n                pass_d4a += 1\\n\\n                # 维度4b: 近10日成交量均值 \\u003e 60日成交量均值\\n                vol_ratio = calculate_volume_ratio(df)\\n                if vol_ratio is None or vol_ratio \\u003c= 1.0:\\n                    continue\\n                pass_d4b += 1\\n\\n                # 维度5: PE \\u003e 0 且 PE \\u003c 100\\n                # 使用mootdx获取PE\\n                pe = get_pe_from_mootdx(code)\\n                if pe is None or not (0 \\u003c pe \\u003c 100):\\n                    # 如果获取不到PE，跳过该股票\\n                    continue\\n                pass_d5 += 1\\n\\n                # 计算综合得分\\n                score = calculate_composite_score(\\n                    stock_ret, ind_return, rsi, bullish_days_count, vol_ratio, pe\\n                )\\n\\n                qualified_stocks.append({\\n                    'code': code,\\n                    'name': name,\\n                    'industry': industry,\\n                    'ind_return': round(ind_return, 2),\\n                    'stock_return': round(stock_ret, 2),\\n                    'rsi': round(rsi, 1),\\n                    'bullish_days': bullish_days_count,\\n                    'vol_ratio': round(vol_ratio, 2),\\n                    'pe': round(pe, 1),\\n                    'score': score\\n                })\\n                print(f\\\"  通过: {code} {name} | 涨幅:{stock_ret:.1f}% | RSI:{rsi:.1f} | 阳线:{bullish_days_count} | 量能比:{vol_ratio:.2f} | PE:{pe:.1f} | 得分:{score}\\\")\\n\\n            print(f\\\"  {industry}漏斗: D2通过{pass_d2} -\\u003e D3a通过{pass_d3a} -\\u003e D3b通过{pass_d3b} -\\u003e D3c通过{pass_d3c} -\\u003e D4a通过{pass_d4a} -\\u003e D4b通过{pass_d4b} -\\u003e D5通过{pass_d5}\\\")\\n\\n        # 按综合得分排序\\n        qualified_stocks.sort(key=lambda x: x['score'], reverse=True)\\n\\n        print(f\\\"\\\\n共找到 {len(qualified_stocks)} 只满足所有条件的股票\\\")\\n\\n        if not qualified_stocks:\\n            output_lines.append(\\\"无符合条件的股票\\\")\\n        else:\\n            for s in qualified_stocks:\\n                line = f\\\"{s['code']},{s['industry']},{s['ind_return']},{s['stock_return']},{s['rsi']},{s['bullish_days']},{s['vol_ratio']},{s['pe']},{s['score']}\\\"\\n                output_lines.append(line)\\n\\n    # 写入结果文件\\n    with open('ultimate_filter.txt', 'w', encoding='utf-8') as f:\\n        f.write('\\\\n'.join(output_lines) + '\\\\n')\\n\\n    print(f\\\"\\\\n结果已写入 ultimate_filter.txt\\\")\\n    print(f\\\"各行业涨幅: {industry_returns}\\\")\\n    print(\\\"技术指标计算：MACD, RSI, MA20, MA60, 均线 均已完成\\\")\\n    print(\\\"PE基本面条件已检查\\\")\\n\\n\\nif __name__ == '__main__':\\n    main()\\n\",\"file_path\":\"/Users/tomato/Documents/potato/project/YFD/results/agent_task/claude/task_20_ultimate_multi_condition/analyze.py\"}","type":"input_json_delta"},"index":1,"type":"content_block_delta"},"session_id":"130141ef-94ad-4bcd-b648-1b10ef40f248","parent_tool_use_id":null,"uuid":"1babee40-92c5-40e5-b0d5-53c8895fb9ed"}
/Users/tomato/Documents/potato/project/YFD/results/agent_task_v1/claude_sonnet/task_20_ultimate_multi_condition/trajectory/stdout.txt:110:{"type":"assistant","message":{"content":[{"id":"toolu_vrtx_01Uu1ZgY5nD1GsEXF92aH61K","input":{"file_path":"/Users/tomato/Documents/potato/project/YFD/results/agent_task/claude/task_20_ultimate_multi_condition/analyze.py","content":"#!/usr/bin/env python3\n\"\"\"\n五维度综合评分超级选股 - 创业板股票筛选\n改进版：使用更完善的行业分类\n\"\"\"\n\nimport pandas as pd\nimport numpy as np\nfrom mootdx.quotes import Quotes\nimport warnings\nwarnings.filterwarnings('ignore')\n\n# 初始化客户端\nclient = Quotes.factory(market='std')\n\ndef get_all_chinext_stocks():\n    \"\"\"获取所有创业板股票\"\"\"\n    stocks_raw = client.stocks(market=0)\n    chinext = []\n    if stocks_raw is not None:\n        for _, row in stocks_raw.iterrows():\n            code = str(row.get('code', '')).strip()\n            if code.startswith('300') or code.startswith('301'):\n                chinext.append({\n                    'code': code,\n                    'name': row.get('name', '').strip()\n                })\n    return chinext\n\ndef classify_industry_by_sw(code, name):\n    \"\"\"\n    更广泛的行业分类 - 基于名称关键词和股票代码特征\n    覆盖医药、新能源、半导体、消费电子四个行业\n    \"\"\"\n    name_str = str(name).upper()\n\n    # ======== 医药行业 ========\n    pharma_kws = [\n        '医药', '医疗', '生物', '制药', '药业', '健康', '医院', '诊断',\n        '基因', '疫苗', '血液', '骨科', '眼科', '口腔', '心脑', '肿瘤',\n        '药', '医', '细胞', '蛋白质', '抗体', '器械', '消毒', '检测',\n        '中药', '西药', '化药', '生化', '体外', '放射', '辅助生殖',\n        '康复', '透析', '植入', '手术', '内窥镜', '影像', '导管',\n        '牙', '骨', '皮肤', '神经', '肿', '糖尿', '高血压'\n    ]\n\n    # ======== 新能源行业 ========\n    energy_kws = [\n        '新能源', '光伏', '风电', '储能', '锂电', '电池', '充电', '太阳能',\n        '氢能', '燃料电池', '特高压', '光能', '锂', '钠离子', '钒',\n        '正极', '负极', '隔膜', '电解液', '电解质', '碳纳米',\n        '硅碳', '磷酸铁锂', '三元材料', '电化学', '双碳',\n        '动力电池', '储电', '逆变', '光储', '风储', '新材料',\n        '导电', '电解槽', '质子交换膜'\n    ]\n\n    # ======== 半导体行业 ========\n    semi_kws = [\n        '半导体', '芯片', '集成电路', '晶圆', '微电子', '存储',\n        '射频', '传感器', '封测', '光刻', '功率', 'LED', '光电',\n        '激光', '红外', '雷达', '导航', '定位', 'GPS', 'MEMS',\n        '功率器件', 'IGBT', '模拟', '数模', '混合信号',\n        '晶体管', '二极管', '三极管', '场效应', '逻辑',\n        'IC设计', '设计', '器件', '制造', '科创'\n    ]\n\n    # ======== 消费电子行业 ========\n    consumer_kws = [\n        '消费电子', '手机', '耳机', '穿戴', '智能终端', '平板',\n        '智能家居', '音响', '游戏', '相机', '摄像', '显示',\n        '触控', '连接器', '天线', '电声', '声学', '蓝牙',\n        'TWS', '智能音箱', '可穿戴', '电视', '显示屏',\n        '背光', '偏光', '光学', '摄像头', '镜头', 'CMOS',\n        'VR', 'AR', '元宇宙', '机器人', '智能硬件'\n    ]\n\n    # 按顺序匹配（防止交叉）- 先匹配更具体的\n    for kw in pharma_kws:\n        if kw in name_str:\n            return '医药'\n    for kw in energy_kws:\n        if kw in name_str:\n            return '新能源'\n    for kw in semi_kws:\n        if kw in name_str:\n            return '半导体'\n    for kw in consumer_kws:\n        if kw in name_str:\n            return '消费电子'\n\n    return None\n\ndef get_stock_history(code, days=70):\n    \"\"\"获取股票历史数据\"\"\"\n    try:\n        df = client.bars(symbol=code, frequency=9, offset=days)\n        if df is None or len(df) < 30:\n            return None\n        return df\n    except Exception as e:\n        return None\n\ndef calculate_returns_20d(df):\n    \"\"\"计算近20日涨幅\"\"\"\n    if df is None or len(df) < 21:\n        return None\n    close = df['close'].values\n    if close[-21] == 0:\n        return None\n    return (close[-1] / close[-21] - 1) * 100\n\ndef calculate_ma(df):\n    \"\"\"计算均线\"\"\"\n    if df is None or len(df) < 60:\n        return None, None\n    close = df['close'].values\n    ma20 = np.mean(close[-20:])\n    ma60 = np.mean(close[-60:])\n    return ma20, ma60\n\ndef calculate_macd(df):\n    \"\"\"计算MACD\"\"\"\n    if df is None or len(df) < 35:\n        return None\n\n    close = pd.Series(df['close'].values)\n    ema12 = close.ewm(span=12, adjust=False).mean()\n    ema26 = close.ewm(span=26, adjust=False).mean()\n    dif = ema12 - ema26\n    dea = dif.ewm(span=9, adjust=False).mean()\n    macd = (dif - dea) * 2\n\n    return macd.values\n\ndef calculate_rsi(df, period=14):\n    \"\"\"计算RSI\"\"\"\n    if df is None or len(df) < period + 5:\n        return None\n\n    close = pd.Series(df['close'].values)\n    delta = close.diff()\n    gain = (delta.where(delta > 0, 0)).rolling(window=period).mean()\n    loss = (-delta.where(delta < 0, 0)).rolling(window=period).mean()\n\n    rs = gain / (loss + 1e-10)\n    rsi = 100 - (100 / (1 + rs))\n\n    return float(rsi.iloc[-1])\n\ndef check_bullish_candles(df, days=10):\n    \"\"\"检查近N日阳线数量\"\"\"\n    if df is None or len(df) < days:\n        return 0\n\n    recent = df.tail(days)\n    bullish = (recent['close'] > recent['open']).sum()\n    return int(bullish)\n\ndef calculate_volume_ratio(df):\n    \"\"\"计算近10日成交量均值/60日成交量均值\"\"\"\n    if df is None or len(df) < 60:\n        return None\n\n    vol = df['volume'].values\n    vol10 = np.mean(vol[-10:])\n    vol60 = np.mean(vol[-60:])\n\n    if vol60 == 0:\n        return None\n    return vol10 / vol60\n\ndef get_pe_from_mootdx(code):\n    \"\"\"从mootdx获取财务数据估算PE\"\"\"\n    try:\n        # 获取实时行情\n        quotes = client.quotes(symbol=[code])\n        if quotes is None or len(quotes) == 0:\n            return None\n\n        # 某些版本mootdx会返回PE相关字段\n        row = quotes.iloc[0]\n        # 尝试多个可能的字段名\n        for field in ['pe', 'PE', 'price_earnings_ratio', 'pe_ttm']:\n            if field in row and row[field] and str(row[field]) not in ['0', '0.0', 'nan', 'None']:\n                return float(row[field])\n    except:\n        pass\n    return None\n\ndef calculate_composite_score(stock_ret, industry_ret, rsi, bullish_days, vol_ratio, pe):\n    \"\"\"\n    综合评分模型 (满分100分)\n    - 行业趋势强度: 15分\n    - 个股超越行业程度: 25分\n    - RSI质量: 15分\n    - 阳线质量: 10分\n    - 量能质量: 10分\n    - PE估值: 10分\n    - 技术基础分(均线+MACD已满足): 15分\n    \"\"\"\n    score = 0.0\n\n    # 维度1: 行业趋势强度 (15分)\n    industry_score = min(15, max(5, (industry_ret - 5) / 5 * 10 + 5))\n    score += industry_score\n\n    # 维度2: 个股超越行业程度 (25分)\n    if industry_ret != 0:\n        exceed_ratio = stock_ret / industry_ret if industry_ret > 0 else 0\n        exceed_score = min(25, max(10, (exceed_ratio - 1.3) * 15 + 10))\n    else:\n        exceed_score = 10\n    score += exceed_score\n\n    # 维度3: RSI评分 (15分) - 越接近60越好\n    rsi_dist = abs(rsi - 60) / 10\n    rsi_score = max(0, 15 * (1 - rsi_dist))\n    score += rsi_score\n\n    # 维度4a: 阳线质量 (10分)\n    bullish_score = min(10, max(6, (bullish_days - 6) * 2 + 6))\n    score += bullish_score\n\n    # 维度4b: 量能比 (10分)\n    if vol_ratio is not None:\n        vol_score = min(10, max(5, (vol_ratio - 1.0) * 5 + 5))\n        score += vol_score\n\n    # 维度5: PE评分 (10分) - 适中PE给高分\n    if pe is not None and 0 < pe < 100:\n        if 15 <= pe <= 60:\n            pe_score = 10 - abs(pe - 35) / 25 * 5\n        elif pe < 15:\n            pe_score = 7  # 极低PE可能有问题\n        else:\n            pe_score = 10 - (pe - 60) / 40 * 10  # 60-100区间递减\n        score += max(0, pe_score)\n\n    # 技术基础分 (15分) - 通过均线和MACD筛选\n    score += 15\n\n    return round(min(100, max(0, score)), 1)\n\n\ndef main():\n    print(\"开始获取创业板股票列表...\")\n\n    # 获取股票列表\n    stocks_list = get_all_chinext_stocks()\n    print(f\"总共获取到 {len(stocks_list)} 只创业板股票\")\n\n    # 行业分类\n    industry_stocks = {\n        '医药': [],\n        '新能源': [],\n        '半导体': [],\n        '消费电子': []\n    }\n\n    for stock in stocks_list:\n        industry = classify_industry_by_sw(stock['code'], stock['name'])\n        if industry:\n            industry_stocks[industry].append(stock)\n\n    total_classified = sum(len(v) for v in industry_stocks.values())\n    print(f\"行业分类结果（共{total_classified}只）：\")\n    for ind, stocks in industry_stocks.items():\n        print(f\"  {ind}: {len(stocks)} 只\")\n\n    # 计算各行业近20日等权涨幅\n    print(\"\\n计算各行业等权涨幅（MA20 vs MA60 涨幅计算）...\")\n    in