[industry]\n\n            pass_d2 = pass_d3a = pass_d3b = pass_d3c = pass_d4a = pass_d4b = pass_d5 = 0\n\n            for stock in stocks:\n                code = stock['code']\n                name = stock['name']\n\n                # 获取历史数据\n                df = get_stock_history(code, days=70)\n                if df is None or len(df) < 60:\n                    continue\n\n                # 维度2: 个股近20日涨幅 > 行业涨幅 × 1.3\n                stock_ret = stock_ret_map.get(code)\n                if stock_ret is None:\n                    stock_ret = calculate_returns_20d(df)\n                if stock_ret is None:\n                    continue\n\n                if stock_ret <= ind_return * 1.3:\n                    continue\n                pass_d2 += 1\n\n                # 维度3a: 价格在MA20和MA60上方\n                ma20, ma60 = calculate_ma(df)\n                if ma20 is None or ma60 is None:\n                    continue\n                current_price = df['close'].values[-1]\n                if current_price <= ma20 or current_price <= ma60:\n                    continue\n                pass_d3a += 1\n\n                # 维度3b: MACD柱状图近5日持续为正且递增\n                macd = calculate_macd(df)\n                if macd is None or len(macd) < 5:\n                    continue\n                macd_5d = macd[-5:]\n                if not all(v > 0 for v in macd_5d):\n                    continue\n                is_increasing = all(macd_5d[i] < macd_5d[i+1] for i in range(len(macd_5d)-1))\n                if not is_increasing:\n                    continue\n                pass_d3b += 1\n\n                # 维度3c: RSI在50-70之间\n                rsi = calculate_rsi(df)\n                if rsi is None or not (50 <= rsi <= 70):\n                    continue\n                pass_d3c += 1\n\n                # 维度4a: 近10日至少6日阳线\n                bullish_days_count = check_bullish_candles(df, days=10)\n                if bullish_days_count < 6:\n                    continue\n                pass_d4a += 1\n\n                # 维度4b: 近10日成交量均值 > 60日成交量均值\n                vol_ratio = calculate_volume_ratio(df)\n                if vol_ratio is None or vol_ratio <= 1.0:\n                    continue\n                pass_d4b += 1\n\n                # 维度5: PE > 0 且 PE < 100\n                # 使用mootdx获取PE\n                pe = get_pe_from_mootdx(code)\n                if pe is None or not (0 < pe < 100):\n                    # 如果获取不到PE，跳过该股票\n                    continue\n                pass_d5 += 1\n\n                # 计算综合得分\n                score = calculate_composite_score(\n                    stock_ret, ind_return, rsi, bullish_days_count, vol_ratio, pe\n                )\n\n                qualified_stocks.append({\n                    'code': code,\n                    'name': name,\n                    'industry': industry,\n                    'ind_return': round(ind_return, 2),\n                    'stock_return': round(stock_ret, 2),\n                    'rsi': round(rsi, 1),\n                    'bullish_days': bullish_days_count,\n                    'vol_ratio': round(vol_ratio, 2),\n                    'pe': round(pe, 1),\n                    'score': score\n                })\n                print(f\"  通过: {code} {name} | 涨幅:{stock_ret:.1f}% | RSI:{rsi:.1f} | 阳线:{bullish_days_count} | 量能比:{vol_ratio:.2f} | PE:{pe:.1f} | 得分:{score}\")\n\n            print(f\"  {industry}漏斗: D2通过{pass_d2} -> D3a通过{pass_d3a} -> D3b通过{pass_d3b} -> D3c通过{pass_d3c} -> D4a通过{pass_d4a} -> D4b通过{pass_d4b} -> D5通过{pass_d5}\")\n\n        # 按综合得分排序\n        qualified_stocks.sort(key=lambda x: x['score'], reverse=True)\n\n        print(f\"\\n共找到 {len(qualified_stocks)} 只满足所有条件的股票\")\n\n        if not qualified_stocks:\n            output_lines.append(\"无符合条件的股票\")\n        else:\n            for s in qualified_stocks:\n                line = f\"{s['code']},{s['industry']},{s['ind_return']},{s['stock_return']},{s['rsi']},{s['bullish_days']},{s['vol_ratio']},{s['pe']},{s['score']}\"\n                output_lines.append(line)\n\n    # 写入结果文件\n    with open('ultimate_filter.txt', 'w', encoding='utf-8') as f:\n        f.write('\\n'.join(output_lines) + '\\n')\n\n    print(f\"\\n结果已写入 ultimate_filter.txt\")\n    print(f\"各行业涨幅: {industry_returns}\")\n    print(\"��术指标计算：MACD, RSI, MA20, MA60, 均线 均已完成\")\n    print(\"PE基本面条件已检查\")\n\n\nif __name__ == '__main__':\n    main()\n"},"name":"Write","type":"tool_use"}],"id":"req_vrtx_011CZpHT2U83DXqhncmSWTiH","model":"claude-sonnet-4-6","role":"assistant","stop_reason":null,"stop_sequence":null,"type":"message","usage":{"input_tokens":10522,"output_tokens":1,"cache_read_input_tokens":24965},"context_management":null},"parent_tool_use_id":null,"session_id":"130141ef-94ad-4bcd-b648-1b10ef40f248","uuid":"e38fc663-9091-4e5d-9f93-b6b0b6770397"}
