dow + lookback_window + 5:\n        return None\n\n    results = []\n\n    # We need at least year_window + lookback_window + 5 days of data\n    # The last 30 trading days are our search window\n    total_len = len(df)\n\n    # Search for breakout in the last 30 trading days\n    # The breakout day index must be at least year_window days from start\n    # and we need 5 more days after it\n\n    search_start = total_len - lookback_window - 5  # start of 30-day window (with 5 days margin)\n    search_end = total_len - 5  # we need 5 days after breakout\n\n    if search_start < year_window:\n        search_start = year_window\n\n    for i in range(search_start, search_end):\n        # 52-week high: max close of the 252 days BEFORE day i\n        past_252_closes = df['close'].iloc[i - year_window:i]\n        max_52w = past_252_closes.max()\n\n        current_close = df['close'].iloc[i]\n\n        # Check if today breaks 52-week high\n        if current_close <= max_52w:\n            continue\n\n        # Check volume condition: avg volume of day i ±2 days vs 60-day avg volume\n        vol_window_start = max(0, i - 2)\n        vol_window_end = min(total_len - 1, i + 2) + 1\n        vol_window = df['volume'].iloc[vol_window_start:vol_window_end]\n        avg_vol_window = vol_window.mean()\n\n        # 60-day average volume (before the breakout day)\n        vol_60d_start = max(0, i - 60)\n        avg_vol_60d = df['volume'].iloc[vol_60d_start:i].mean()\n\n        if avg_vol_window <= 1.5 * avg_vol_60d:\n            continue\n\n        # Check follow-through: next 5 days, at least 3 close above breakout price\n        if i + 5 >= total_len:\n            continue\n\n        next_5_closes = df['close'].iloc[i+1:i+6]\n        if len(next_5_closes) < 5:\n            continue\n\n        days_above = (next_5_closes > current_close).sum()\n        if days_above < 3:\n            continue\n\n        # Calculate 5-day return (5th day close / breakout day close - 1) * 100\n        close_day5 = df['close'].iloc[i + 5]\n        gain_5d = (close_day5 / current_close - 1) * 100\n\n        breakout_date = df['datetime'].iloc[i]\n        if hasattr(breakout_date, 'strftime'):\n            date_str = breakout_date.strftime('%Y-%m-%d')\n        else:\n            date_str = str(breakout_date)[:10]\n\n        results.append({\n            'date': date_str,\n            'breakout_price': round(current_close, 2),\n            'gain_5d': round(gain_5d, 2),\n            'idx': i\n        })\n\n    if not results:\n        return None\n\n    # Return only the first breakout\n    return results[0]\n\n\ndef main():\n    print(\"Getting GEM stock list...\")\n    gem_codes = get_gem_stocks()\n    print(f\"Total GEM stocks: {len(gem_codes)}\")\n\n    client = Quotes.factory(market='std')\n\n    output_rows = []\n    total = len(gem_codes)\n\n    for idx, code in enumerate(gem_codes):\n        if idx % 100 == 0:\n            print(f\"Processing {idx}/{total}...\")\n\n        # Need: 252 (52w) + 30 (search) + 5 (follow-through) + 60 (vol avg) buffer\n        # 252 + 30 + 5 = 287, but 60d vol uses days before breakout so it's within 252\n        # Use 320 to be safe\n        df = get_daily_data(client, code, count=320)\n\n        result = analyze_stock(df, lookback_window=30, year_window=252)\n\n        if result:\n            output_rows.append(f\"{code},{result['date']},{result['breakout_price']},{result['gain_5d']}\")\n            print(f\"  FOUND: {code} on {result['date']} at {result['breakout_price']}, 5d gain: {result['gain_5d']}%\")\n\n    print(f\"\\nTotal stocks meeting all 3 conditions: {len(output_rows)}\")\n\n    output_path = '/Users/tomato/Documents/potato/project/YFD/results/agent_task/claude/task_19_52week_high_followthrough/breakout_followthrough.txt'\n\n    with open(output_path, 'w', encoding='utf-8') as f:\n        if output_rows:\n            for row in output_rows:\n                f.write(row + '\\n')\n        else:\n            f.write(\"无符