usive\n        avg_vol_window = volumes[vol_window_start:vol_window_end].mean()\n\n        # 60-day avg volume: the 60 days before breakout day\n        vol_60d_start = max(0, i - 60)\n        avg_vol_60d = volumes[vol_60d_start:i].mean()\n\n        if avg_vol_window <= 1.5 * avg_vol_60d:\n            continue\n\n        # Condition 3: at least 3 of next 5 days close above breakout price\n        next_5_closes = closes[i+1:i+6]\n        if len(next_5_closes) < 5:\n            continue\n\n        days_above = int((next_5_closes > current_close).sum())\n        if days_above < 3:\n            continue\n\n        # Calculate 5-day return: 5th day close / breakout day close - 1\n        close_day5 = closes[i + 5]\n        gain_5d = round((close_day5 / current_close - 1) * 100, 2)\n\n        breakout_date = df['datetime'].iloc[i]\n        date_str = str(breakout_date)[:10]\n\n        # Only return the first breakout found\n        return {\n            'date': date_str,\n            'breakout_price': round(float(current_close), 2),\n            'gain_5d': gain_5d,\n        }\n\n    return None\n\n\ndef main():\n    print(\"Getting GEM stock list...\", flush=True)\n    gem_codes = get_gem_stocks()\n    print(f\"Total GEM stocks: {len(gem_codes)}\", flush=True)\n\n    client = Quotes.factory(market='std')\n\n    output_rows = []\n    total = len(gem_codes)\n\n    for idx, code in enumerate(gem_codes):\n        if idx % 200 == 0:\n            print(f\"Processing {idx}/{total}...\", flush=True)\n\n        df = get_daily_data(client, code, count=320)\n        result = analyze_stock(df, lookback_window=30, year_window=252)\n\n        if result:\n            row = f\"{code},{result['date']},{result['breakout_price']},{result['gain_5d']}\"\n            output_rows.append(row)\n            print(f\"  FOUND: {row}\", flush=True)\n\n    print(f\"\\nTotal stocks meeting all 3 conditions: {len(output_rows)}\", flush=True)\n\n    output_path = '/Users/tomato/Documents/potato/project/Y