t = closes[-period:]\n\n    middle = np.mean(recent)\n    std = np.std(recent, ddof=0)  # Population std (matches typical Bollinger calculation)\n\n    if middle == 0:\n        return None\n\n    upper = middle + 2 * std\n    lower = middle - 2 * std\n\n    width = (upper - lower) / middle\n    return width\n\n\ndef main():\n    print(\"Getting GEM stocks...\")\n    client = Quotes.factory(market='std')\n\n    # Get SZ market stocks\n    sz_stocks = client.stocks(market=0)\n\n    gem_stocks = []\n    if sz_stocks is not None and len(sz_stocks) > 0:\n        for _, row in sz_stocks.iterrows():\n            code = str(row.get('code', '')).strip()\n            if code.startswith('300') or code.startswith('301'):\n                gem_stocks.append(code)\n\n    print(f\"Found {len(gem_stocks)} GEM stocks\")\n\n    if len(gem_stocks) == 0:\n        print(\"No GEM stocks found, trying alternative method...\")\n        return\n\n    # For each stock, get 50 days of data (need at least 20 for Bollinger)\n    # We need 30 trading days of data per task, but for 20-day SMA we need at least 20\n    # Task says: \"最近30个交易日内\", so we check if in the last 30 trading days\n    # the Bollinger band width (calculated with 20-day SMA) < 5%\n\n    squeeze_count = 0\n    valid_count = 0\n    errors = 0\n\n    print(\"Calculating Bollinger Bands...\")\n\n    for i, code in enumerate(gem_stocks):\n        if i % 100 == 0:\n            print(f\"Progress: {i}/{len(gem_stocks)}, squeeze so far: {squeeze_count}\")\n\n        # Get recent 50 days to ensure we have 30 trading days + buffer for 20-day SMA\n        closes = get_stock_history(client, code, days=50)\n\n        if closes is None or len(closes) < 20:\n            errors += 1\n            continue\n\n        # Calculate Bollinger width using last 20 days of the 30-day window\n        # Task: get last 30 trading days, compute 20-day SMA (which uses the 20 most recent)\n        # The \"latest\" Bollinger width = width on the last day usi